INSERT INTO "public"."posts" ("id", "author_id", "breed", "type", "tag", "content_text", "title", "created_at", "updated_at", "place_id") VALUES
	('ecdffcff-c459-4323-911f-2124587fd927', 'f1784754-de47-416e-973b-4cc3b38ac153', 'AUSTRALIAN_SHEPHERD', 'UPDATE_STORY', 'PLAYDATE', 'Rigby absolutely lost his mind at Dog Beach. First five minutes he just stood at the water''s edge barking at the waves like he was personally offended by them. Then some golden retriever ran past and he was off.
INSERT INTO "public"."comments" ("id", "post_id", "author_id", "content_text", "created_at") VALUES
	('ab5203d1-7170-4dde-91d5-6ee03cd359f0', '8a10cfc1-cae1-45f6-9b54-a682b4066f2d', 'f1784754-de47-416e-973b-4cc3b38ac153', 'Rigby did this with my sister''s kid for a couple of months. Pure herding instinct – they need a job and the toddler is just the most available option. More mental enrichment helped us more than trying to train it out directly.', '2026-04-14 01:08:00+00'),
	('a012158a-806d-4c22-91ac-db4a81cadb74', '8a10cfc1-cae1-45f6-9b54-a682b4066f2d', 'c7b31f6b-6b96-4cae-a8de-6633dc9f121f', 'Pepper went through this phase too. We added a "place" command so she had somewhere to go when kids were in the yard. Didn''t fix the instinct but gave us a reliable redirect.', '2026-04-14 01:32:00+00'),
	('b2c3b617-8cd7-4b30-a6d8-90318f0fbdcb', '8a10cfc1-cae1-45f6-9b54-a682b4066f2d', '2101bc11-1686-4c59-b068-8a60814631dd', 'Wren did this at a playground once, a bit mortifying. More structured trail work and it dialed back a lot over the following months. Not gone but manageable.', '2026-04-14 02:05:00+00'),
	('d76e06d8-da46-44b0-b265-d877a60f3396', '19d37e34-c06f-47d1-90a4-625a778b24ef', 'f1784754-de47-416e-973b-4cc3b38ac153', 'We went through something similar with Rigby. Keeping weight lean and sticking to lower-impact trail walks made a real difference. Our vet also recommended fish oil around the same time.', '2026-04-14 01:10:00+00'),
	('d21cb25d-a20b-4cf7-877f-b64e47736dc7', '19d37e34-c06f-47d1-90a4-625a778b24ef', 'c7b31f6b-6b96-4cae-a8de-6633dc9f121f', 'Get a second opinion if you haven''t yet. Pepper had some flagged concerns at 2 and a second vet read the X-rays differently. Joint supplements early seemed to help her.', '2026-04-14 01:42:00+00'),
	('5ff209bc-24b0-482e-8ff8-4282faef9cca', '19d37e34-c06f-47d1-90a4-625a778b24ef', '10e6d031-86f6-46e0-8161-6c4efc543801', 'A friend''s aussie went through this at the same age. Hydrotherapy was a big part of their management plan. Expensive but worth asking your vet about.', '2026-04-14 02:20:00+00'),
	('8686a7b5-e0b9-48c3-aaae-9b6fccac46b5', '1f80f9aa-a307-4c19-bd0e-81c45f52925d', '363de776-84af-42ff-ba57-6cbac5b9c1ed', 'Long line work before ever going off-leash. We practiced recall in a park with dogs at distance for months before Clover was reliable near them. She still has a delay when she really wants to meet someone but she does come back.', '2026-04-14 01:12:00+00'),
	('07fd9a9e-4aa0-4db1-a756-719420227779', '1f80f9aa-a307-4c19-bd0e-81c45f52925d', 'c7b31f6b-6b96-4cae-a8de-6633dc9f121f', 'Only call recall when you know you can get it at first – calling and not getting it teaches them they can ignore it. We built ours up very slowly in lower-distraction environments before adding dogs.', '2026-04-14 01:40:00+00'),
	('51d4dccb-b002-4256-92e7-a3879c529403', '1f80f9aa-a307-4c19-bd0e-81c45f52925d', '2101bc11-1686-4c59-b068-8a60814631dd', 'Freeze-dried chicken reserved only for recall helped with Wren. She knows that specific call means something special is coming. Took consistent months of work.', '2026-04-14 02:15:00+00'),
	('a85f4579-255c-4778-a5ae-e4979235f7d2', 'd90cb51c-695a-4cb0-8a67-3b3059542d10', 'f1784754-de47-416e-973b-4cc3b38ac153', 'We followed the 5-min per month of age guideline – so about 25 minutes twice a day at that age. Free play in a yard is different from forced walking or running. Rigby is 2 with no joint issues and I was very careful early on.', '2026-04-14 01:12:00+00'),
	('f6f433a8-6662-42b7-a46f-466c1322161e', 'd90cb51c-695a-4cb0-8a67-3b3059542d10', '79198548-1ef4-4433-a694-6f9ae60ffe44', 'Seriously follow the 5-minute rule. A friend overdid it with an aussie and had early joint issues. More mental enrichment at that age, less running.', '2026-04-14 01:45:00+00'),
	('3e4f4873-8e94-4e15-96c6-701e8314492f', 'e4d60c24-954c-4340-ad77-41866a260fc2', '363de776-84af-42ff-ba57-6cbac5b9c1ed', 'Undercoat rake first, then a slicker. Do it outside because it''s a lot. Don''t skip weeks in spring – Clover loses what feels like half her body weight in shed.', '2026-04-14 01:10:00+00'),
	('243048b4-a009-476b-bb87-a40ade7324a5', 'e4d60c24-954c-4340-ad77-41866a260fc2', 'c7b31f6b-6b96-4cae-a8de-6633dc9f121f', 'We use the King Komb and it''s been great for Pepper''s coat – gentler than the Furminator. Line brushing in sections is worth looking up if you haven''t tried it.', '2026-04-14 01:45:00+00'),
	('1998bb02-54a1-4a20-85e3-2028719430bc', 'e2e594b6-405f-4bae-be29-f971538bd3a1', 'f1784754-de47-416e-973b-4cc3b38ac153', 'Rigby claimed the other half of my standing desk mat and stares at me whenever I shift. We have matching setups now.', '2026-04-14 01:15:00+00'),
	('aee17999-7803-4b35-912f-c67bc36a4d6c', 'e2e594b6-405f-4bae-be29-f971538bd3a1', '2101bc11-1686-4c59-b068-8a60814631dd', 'Wren figured out that if she sleeps on my feet I don''t get up as fast. They''re scheming.', '2026-04-14 01:50:00+00'),
	('c44c4744-8e1f-4d90-82d1-1aa43cacbe5c', '7e63d869-3cb0-4c5f-98e0-3cc59677ca0f', '363de776-84af-42ff-ba57-6cbac5b9c1ed', 'We''re likely in! Clover has been overdue for some Aussie time. What time usually?', '2026-04-14 01:05:00+00'),
	('5b5408da-41db-45de-a600-58eb2f47a26c', '7e63d869-3cb0-4c5f-98e0-3cc59677ca0f', 'f1784754-de47-416e-973b-4cc3b38ac153', 'Rigby would lose her mind. We''ll try to come.', '2026-04-14 01:18:00+00'),
	('f0b59ca4-1ee5-4835-a615-23566196d9b1', '5e563d41-0305-4068-8109-d9c7325ac7a8', 'bba2736b-1f5f-4e37-8ca9-2b71be7ef598', 'Frank was the same at that age. The frantic phase settled around 10-11 months. Hang in there.', '2026-04-14 01:10:00+00'),
	('9836f6a8-c19d-40ad-8d9f-03f3b6bb472b', '5e563d41-0305-4068-8109-d9c7325ac7a8', '9089ed39-9b59-42eb-b14d-8d7a97d02298', 'Pretzel was chaos for the first year. At some point it just calms into a different kind of chaos. Pretty standard for 6 months.', '2026-04-14 01:36:00+00'),
	('55a07335-e99c-4129-abcc-72a5a11b0d3d', '5e563d41-0305-4068-8109-d9c7325ac7a8', 'fe434db5-2ab5-43e4-b309-e8b43e10b7db', 'Bao did the same zoomie-bite-sleep cycle for months. Totally normal from what I''ve seen.', '2026-04-14 02:02:00+00'),
	('e4033512-f4fb-4d35-b08a-b0b5c9419322', 'd22b7add-3a68-4b1b-a725-2421d8deab25', 'e904a679-c785-48b9-8f81-4606372df469', 'Mine has the highest spot on the back of the couch. Full surveillance mode starting at 7am.', '2026-04-14 01:05:00+00'),
	('95e94304-7679-4feb-ad60-8d13818a546a', 'd22b7add-3a68-4b1b-a725-2421d8deab25', 'cc1cf6c1-ff2c-4e13-ab1b-53e75f2626f1', 'Mochi has rotating positions depending on which part of the street needs watching. Very serious work.', '2026-04-14 01:25:00+00'),
	('ab95d88e-42de-4ac9-ad6d-c7ff1b9e94d0', 'fa86c298-8d59-4053-b884-7df187c4e7e1', 'fe434db5-2ab5-43e4-b309-e8b43e10b7db', 'Mission Valley Animal Hospital has a vet who sees a lot of dachshunds. Worth calling ahead to ask specifically.', '2026-04-14 01:08:00+00'),
	('56974831-43e9-4343-89c4-a261f7663ecc', 'fa86c298-8d59-4053-b884-7df187c4e7e1', 'bba2736b-1f5f-4e37-8ca9-2b71be7ef598', 'We went to VCA Mission Valley – they were familiar with the breed and not alarmist. Ask if they have experience with IVDD specifically.', '2026-04-14 01:32:00+00'),
	('4557658f-e4e0-4de1-acce-6a9c70bede59', 'fa86c298-8d59-4053-b884-7df187c4e7e1', 'e628ab57-343b-408e-a5b3-ea4df6ac7498', 'Our vet near Mission Hills has worked with dachshund rescues and knows the breed well. Happy to DM the name.', '2026-04-14 02:00:00+00'),
	('bb98534f-3aee-4376-9be1-00f242b5466b', '8a660086-da51-47fc-b2b7-7619d8737f4c', 'bba2736b-1f5f-4e37-8ca9-2b71be7ef598', 'Keep encounters very short and positive before they tip over. Frank learned that brief calm exposures were safe. Duration matters a lot at first.', '2026-04-14 01:15:00+00'),
	('29a18c4e-1950-40b5-9984-02dd61ccf988', '8a660086-da51-47fc-b2b7-7619d8737f4c', 'e904a679-c785-48b9-8f81-4606372df469', 'Slow exposure is the right call. Let her choose to approach, never force it. Yuki took about 4-5 months of keeping distance and rewarding calm before we saw real change.', '2026-04-14 01:45:00+00'),
	('c4329c61-7b90-4e20-97f8-44d5087351b3', 'bb745e8b-6512-4425-87e6-110c9d19b692', 'bba2736b-1f5f-4e37-8ca9-2b71be7ef598', 'Frank is in if it''s not too crowded. He does better in smaller groups.', '2026-04-14 01:05:00+00'),
	('8368c6ac-b414-4c11-b943-897b81617049', 'bb745e8b-6512-4425-87e6-110c9d19b692', 'e904a679-c785-48b9-8f81-4606372df469', 'This sounds perfect. What time are you thinking?', '2026-04-14 01:20:00+00'),
	('296dbf82-63e4-46c2-b68d-f58fd21a307b', 'e9acbb2a-dbf8-4b9a-b8b1-c7dda4da6e37', 'bba2736b-1f5f-4e37-8ca9-2b71be7ef598', 'Frank has the same alarm bark when the garden hose comes out. Total conviction that it''s an attack.', '2026-04-14 01:10:00+00'),
	('48d16be6-0228-4773-bb91-f51289152f53', 'e9acbb2a-dbf8-4b9a-b8b1-c7dda4da6e37', 'cc1cf6c1-ff2c-4e13-ab1b-53e75f2626f1', 'The feet got wet anyway. Perfect ending.', '2026-04-14 01:30:00+00'),
	('d327ff10-e89e-4f63-9150-69857a2d7955', 'f72ce188-8e8b-4c8f-b03b-365d4f41303b', '1bbafccc-ba85-4a09-8200-d20825b0a54e', 'Ares does this too even with our parents. We''ve been working on "place" when the bell rings so he has somewhere to go instead of rushing the door. Still a work in progress but better.', '2026-04-14 01:15:00+00'),
	('4e442d7c-b1b4-48e4-a211-81bf6d95639b', 'f72ce188-8e8b-4c8f-b03b-365d4f41303b', '83e3931a-ef76-4731-9549-929b960acb5e', 'We started having guests knock more softly and approach slowly. Less of a startle response meant less of a bark spike. Sounds counterintuitive but it worked for Zelda.', '2026-04-14 01:45:00+00'),
	('9b3eaf01-ba57-4836-978b-41d38db0d2af', 'f72ce188-8e8b-4c8f-b03b-365d4f41303b', 'd620bae3-e3f2-4de7-804b-9ac1a39fbcce', 'Ghost barks at everyone including us sometimes. It''s an alert instinct. If he knows the person and still does it, he might just need a release behavior when people arrive.', '2026-04-14 02:18:00+00'),
	('3ef8afa8-163f-408e-a450-83a983b91f73', 'e0f0f96d-d080-4a49-b0f2-1d29c4c7f555', '83e3931a-ef76-4731-9549-929b960acb5e', 'Zelda is exactly like this. GSDs have a "what''s in it for me" mode. High-value treats only in challenging situations and never ask for something you can''t enforce.', '2026-04-14 01:10:00+00'),
	('bfa7985d-cbf1-4af8-ba32-55da72688c61', 'aa929f7c-b376-4e7f-ad9f-2e02d1f5294b', '1c147082-eeda-4c2d-9294-399e02fdfcf4', 'For a first dog, yes. Even 4-6 group classes gives you a framework that pays off for years.', '2026-04-14 01:10:00+00'),
	('9a9f69ed-f711-44ee-b2fe-5cbf48c6d62d', 'e0f0f96d-d080-4a49-b0f2-1d29c4c7f555', '2827fbe2-4772-41a5-9d67-80c11ae24e3b', 'Nora had the same selective engagement. Shorter, snappier sessions worked much better than long drilling. If you feel them checking out, stop before they disengage on their own.', '2026-04-14 01:40:00+00'),
	('bd98d84f-69d5-49c5-8ab0-384514eab8a6', 'e0f0f96d-d080-4a49-b0f2-1d29c4c7f555', 'a8988812-4db4-4283-9385-b9d284affbb6', 'Bruno does this with "down" specifically. We went back to basics and rebuilt from the ground. Sometimes the foundation drifts and they test you.', '2026-04-14 02:12:00+00'),
	('7a2030c3-e2f0-4485-8337-4c8dfa8a3eac', '84bcce5c-dc91-4673-8628-601ef55f7a19', '1bbafccc-ba85-4a09-8200-d20825b0a54e', 'Ares is the same. We stopped doing face-to-face on-leash intros entirely. Parallel walking at distance first, let them sniff at an angle if at all. Makes a huge difference.', '2026-04-14 01:15:00+00'),
	('e08d8650-9081-467c-bacd-3c4cbee7f9af', '84bcce5c-dc91-4673-8628-601ef55f7a19', 'd620bae3-e3f2-4de7-804b-9ac1a39fbcce', 'Parallel walk, not head-on – changed everything for Ghost. Head-on approaches are inherently confrontational. Side-by-side with distance, then gradually drift closer.', '2026-04-14 01:45:00+00'),
	('c0b5ae17-8cbb-4a34-86c3-814f9b483519', '84bcce5c-dc91-4673-8628-601ef55f7a19', 'a8988812-4db4-4283-9385-b9d284affbb6', 'Bruno can look like he''s escalating when he''s actually just over-aroused. They can look similar. A trainer helped us read him better and respond differently.', '2026-04-14 02:18:00+00'),
	('1b7703d0-8040-48b2-b509-f73dfb6f66cf', '8c9a7c16-d51d-4d3d-8ff8-46e32d7b2d3e', '1bbafccc-ba85-4a09-8200-d20825b0a54e', 'We''d love this. Ares needs a real run.', '2026-04-14 01:05:00+00'),
	('4ec1f486-6e05-4599-9589-3fed0cb54ebf', '8c9a7c16-d51d-4d3d-8ff8-46e32d7b2d3e', 'd620bae3-e3f2-4de7-804b-9ac1a39fbcce', 'Ghost does okay with well-socialized dogs. We''ll try to make it.', '2026-04-14 01:20:00+00'),
	('5888f94c-f9f8-4849-a9d4-977cb73e60ee', '947d65a7-7a92-4412-a852-3d50b99570a2', '1bbafccc-ba85-4a09-8200-d20825b0a54e', 'This is such a win. Ares took a long time before he was comfortable at a beach with that many dogs. It really does get better.', '2026-04-14 01:10:00+00'),
	('f73ec76f-4322-4e24-a992-f5e884a6eee2', '947d65a7-7a92-4412-a852-3d50b99570a2', 'a8988812-4db4-4283-9385-b9d284affbb6', 'The perimeter patrol phase is so real for this breed. Bruno still does it at new places.', '2026-04-14 01:35:00+00'),
	('a3e0feaf-a83e-45c7-9b4d-87b1fa1936ce', 'c520567a-924c-4cfe-ad7a-482dbae64174', '0bffa949-5c70-4bb5-83ae-adb645188fdb', 'After two huskies I''ve made peace with off-leash only in fully enclosed areas. Mako has excellent recall in our yard and basically none on a trail. The breed has a hard-wired go-explore mode that overrides training for a lot of dogs.', '2026-04-14 01:10:00+00'),
	('9650dba7-df0f-458a-98ed-f8641e5c54ea', 'c520567a-924c-4cfe-ad7a-482dbae64174', '835ebfc8-c69c-4681-ba39-05d6c430dd56', 'Sasha has decent recall in controlled settings and almost none outside. A trainer told us to stop chasing and make coming back more exciting than whatever she was running toward. It helped but she still has a delay.', '2026-04-14 01:40:00+00'),
	('2cc33c79-b470-4537-b8a9-65f2d957c95f', 'c520567a-924c-4cfe-ad7a-482dbae64174', '32e2d069-f4a2-4117-9d05-813735304ac7', 'Trainer told us the most honest thing: some huskies just don''t have reliable off-leash recall and that''s okay. Reframed things for us. We do long-line work and call it a day.', '2026-04-14 02:15:00+00'),
	('64854a3e-d919-4b2d-936d-0be1967de14b', 'c520567a-924c-4cfe-ad7a-482dbae64174', '2c5bf077-cc49-4add-a920-8742e8bb0984', 'Nova literally looks at me, then at the field, then makes a decision. Outside she''s always on a 30-foot line.', '2026-04-14 02:42:00+00'),
	('67d930ec-d059-41d3-8777-b35a19707cf0', 'b40e8185-24de-4bf3-bba2-fbebe40bb2ca', '0bffa949-5c70-4bb5-83ae-adb645188fdb', 'Mako did this for the first 8 months. We worked through it with very short departures and came back before he escalated. A white noise machine outside the door also helped.', '2026-04-14 01:15:00+00'),
	('ee7f2675-6956-4488-895f-241c24f62c10', 'b40e8185-24de-4bf3-bba2-fbebe40bb2ca', 'b6b055b9-9850-4cef-ad8e-78ccd7442b81', 'The neighbor note is rough. We sent ours a text to warn them when we''d be out. Not a real fix but it helped our relationship while we worked on the actual problem.', '2026-04-14 01:45:00+00'),
	('8f04626a-3342-4845-bac3-6f3f710aff8b', 'b40e8185-24de-4bf3-bba2-fbebe40bb2ca', '835ebfc8-c69c-4681-ba39-05d6c430dd56', 'Frozen stuffed Kongs left at the door at departure gave Sasha something to do in those first few minutes. The howling came later and we were usually back by then.', '2026-04-14 02:18:00+00'),
	('2e29f1dc-d96f-4c3a-be52-003980406360', '61ae1e06-33e7-4cba-9f6d-f5b06ce1acbc', '835ebfc8-c69c-4681-ba39-05d6c430dd56', '5am walks before sunrise, frozen treats midday, kiddie pool in the shade. Sasha manages but you have to be the one managing it because she''ll never ask to slow down when she should.', '2026-04-14 01:10:00+00'),
	('0bc70101-6fbe-48a9-b231-c595a7745da7', '61ae1e06-33e7-4cba-9f6d-f5b06ce1acbc', '32e2d069-f4a2-4117-9d05-813735304ac7', 'We moved all exercise to early morning and evening only. Always carry water. Huskies will push past their limit before they stop on their own.', '2026-04-14 01:40:00+00'),
	('c6b0faec-7d2f-4d0f-855d-05d58690f875', '61ae1e06-33e7-4cba-9f6d-f5b06ce1acbc', '2c5bf077-cc49-4add-a920-8742e8bb0984', 'Cooling mat for the afternoons, and keep the coat full – shaving is tempting but it doesn''t actually help them cool and can cause sunburn.', '2026-04-14 02:18:00+00'),
	('6dba89f1-7ddf-47b1-9fa9-69ce075b82d3', '630560e4-30f7-434a-b2f9-a9ce288b67ba', 'b6b055b9-9850-4cef-ad8e-78ccd7442b81', 'Yes this is just husky. Mochi has full conversations about things she disagrees with. The solution is to not engage with the argument.', '2026-04-14 01:10:00+00'),
	('3842114d-2344-4fa5-bf52-bc8a4350be42', '630560e4-30f7-434a-b2f9-a9ce288b67ba', '0bffa949-5c70-4bb5-83ae-adb645188fdb', 'Mako does this when I ask him to do something he doesn''t want to do. Full protest vocalization. We just say "yes I know, do it anyway" and eventually he does.', '2026-04-14 01:40:00+00'),
	('c9a6cd98-b205-4870-aff5-17b9c2df0921', 'ed058173-024f-417e-a33f-f2f85fde74ce', '0bffa949-5c70-4bb5-83ae-adb645188fdb', 'Mako found a gap I didn''t know about in my first month. Did a full perimeter check after that. They''re engineers.', '2026-04-14 01:10:00+00'),
	('b7701c71-0dfc-4f0f-89d0-1d3c693592d1', 'ed058173-024f-417e-a33f-f2f85fde74ce', '2c5bf077-cc49-4add-a920-8742e8bb0984', 'Huskies will find every structural weakness. I treated my yard like a security audit when I got Nova and still found two gaps I''d missed.', '2026-04-14 01:38:00+00'),
	('36b47033-e3af-4159-8bc1-f29b26903c1b', '21bfecb1-dc58-41d9-a8ee-ed1dce43bf41', '835ebfc8-c69c-4681-ba39-05d6c430dd56', 'We''ll try to make this. Sasha does well at Grape Street.', '2026-04-14 01:05:00+00'),
	('8df9af74-c4f3-48d9-8795-2b71837ae2f5', '21bfecb1-dc58-41d9-a8ee-ed1dce43bf41', '0bffa949-5c70-4bb5-83ae-adb645188fdb', 'Mako is in. He''s been cooped up this week.', '2026-04-14 01:20:00+00'),
	('d179856b-e9d9-410d-bfb4-1832d3cfd0a4', '12df68d0-e90b-4cd4-8743-c80a46a4c76f', '1c147082-eeda-4c2d-9294-399e02fdfcf4', 'Every 6-8 weeks minimum. I went 12 once and it was a disaster. Our groomer said 8 is the max window if you''re brushing at home 2-3 times a week.', '2026-04-14 01:10:00+00'),
	('b33afad8-8f40-40bf-9731-9e05b4421f7f', '12df68d0-e90b-4cd4-8743-c80a46a4c76f', '8f1ae823-159f-44d9-9acc-20310c49f1fa', 'Otto gets bad matting behind the ears if we push past 8 weeks. 6 is our sweet spot when we''re brushing consistently at home.', '2026-04-14 01:40:00+00'),
	('53ff45ff-6d76-41c2-8c19-3c63cd9075d2', '12df68d0-e90b-4cd4-8743-c80a46a4c76f', '0b9a2af8-19ac-4819-ba8d-2ed9bf64f2f8', 'Depends on coat type too. Ziggy''s fleece coat mats faster than a wavy coat. 6 weeks for us.', '2026-04-14 02:10:00+00'),
	('2342efeb-097e-406e-bbd0-57fd678cfe9a', '7a0ce65e-6aad-47a6-8808-09021e660a39', '1c147082-eeda-4c2d-9294-399e02fdfcf4', 'We made the rule that no one greets our dog until all four paws are on the ground – including us. Inconsistency from guests is the biggest problem. Brief everyone when they come in.', '2026-04-14 01:15:00+00'),
	('79de1e3d-31e0-40ec-83f3-d2b8d35a62e2', '7a0ce65e-6aad-47a6-8808-09021e660a39', '8f1ae823-159f-44d9-9acc-20310c49f1fa', 'Four on the floor helped Otto eventually but it takes months of everyone enforcing it. The breed is so social they just need a consistent alternative behavior, not just a correction.', '2026-04-14 01:45:00+00'),
	('deddca25-803d-475e-93bc-340fb1a2389e', '7a0ce65e-6aad-47a6-8808-09021e660a39', '0b9a2af8-19ac-4819-ba8d-2ed9bf64f2f8', 'Ziggy still does it with new people after two years. We''ve mostly accepted that enthusiastic is part of the package.', '2026-04-14 02:18:00+00'),
	('ac9a2aa5-25db-42b2-ab15-80c1bd87c776', '881051cc-c176-4c38-b524-815909f661f5', '1c147082-eeda-4c2d-9294-399e02fdfcf4', 'Remi was around 2.5. Something shifted and he became more settled. Still energetic but not frantic.', '2026-04-14 01:10:00+00'),
	('3a012566-96a3-4682-af93-d741fd19594d', '881051cc-c176-4c38-b524-815909f661f5', '8f1ae823-159f-44d9-9acc-20310c49f1fa', 'Otto is 3 and I''d say 70% calm. The other 30% comes out when new people arrive.', '2026-04-14 01:35:00+00'),
	('9b8c1923-7dcf-4e12-9fbb-d88e38fbbc75', '881051cc-c176-4c38-b524-815909f661f5', '0b9a2af8-19ac-4819-ba8d-2ed9bf64f2f8', 'Our vet said 3 for doodles because of the poodle side. She was right – there''s a real shift around 2.5-3.', '2026-04-14 02:02:00+00'),
	('b0b7989c-093d-401d-97ae-f0578f155601', 'b2af5d7b-9d6c-4de6-b3c8-2c893bbff9a8', '8f1ae823-159f-44d9-9acc-20310c49f1fa', 'We had the exact same situation. The ''hypoallergenic'' marketing is... optimistic. Our doodle definitely triggers allergies. Hope she''s finding workarounds.', '2026-04-14 01:10:00+00'),
	('1e68a40e-824c-4c6f-9f95-64c5d99c6ee2', 'b2af5d7b-9d6c-4de6-b3c8-2c893bbff9a8', '1e9bcdef-d5e4-40e3-aa82-9d38c7ef89d9', 'Clementine sheds more than I was told to expect. Coats vary a lot even within the same litter.', '2026-04-14 01:40:00+00'),
	('1bea5898-dcc1-4fb0-b085-12c68724cc2b', 'aa929f7c-b376-4e7f-ad9f-2e02d1f5294b', '1e9bcdef-d5e4-40e3-aa82-9d38c7ef89d9', 'I waited too long with Clementine. The habits she built in the first 6 months were hard to undo. Even a single consult is worth it to start right.', '2026-04-14 01:40:00+00'),
	('98ee5e33-b742-428d-af7e-d2f5d951a551', '21edd00d-e8a6-4766-a49d-76f5fdb6af50', '1e9bcdef-d5e4-40e3-aa82-9d38c7ef89d9', 'Clementine would love Morley Field. We''re in if the timing works.', '2026-04-14 01:05:00+00'),
	('9b364442-bc31-449d-93b4-dab1bded0e1c', '21edd00d-e8a6-4766-a49d-76f5fdb6af50', '08e97e83-10b9-42e9-adf3-59f73e37826d', 'Hazel needs this. Count us in.', '2026-04-14 01:20:00+00'),
	('e7cc01bf-e3e3-41f0-afb5-b1d80f3fe138', 'e4c656d3-3b2a-4e36-bded-29db34111577', '9f9acd96-a9ae-480b-ab1b-93cc05ebfb13', 'We do annual comprehensive bloodwork and a chest X-ray now. Chester''s oncologist mentioned the Golden Retriever Lifetime Study – not a screening tool but it gave us context for what to watch.', '2026-04-14 01:15:00+00'),
	('2c8811d4-c80c-4de9-8e38-605c0f145a58', 'e4c656d3-3b2a-4e36-bded-29db34111577', '66694e3f-9988-4378-9df3-671525ae0404', 'We started full panels at 4 because of the breed stats. Vet said baseline data matters more for goldens than most breeds. Hard to have that conversation when they''re young but it''s worth it.', '2026-04-14 01:45:00+00'),
	('d249d832-840e-45c0-8c42-41fd45c86c9a', 'e4c656d3-3b2a-4e36-bded-29db34111577', '81e086b1-20aa-47ed-b286-dca03731a5df', 'The early bloodwork builds a baseline so changes later are more visible. We do the full panel at 5 and up. Such an important topic for this breed.', '2026-04-14 02:18:00+00'),
	('784c3ef9-60fd-4ecb-b2a0-d47a7e556c98', '36a5db88-a8a6-477d-9841-c4578ee64ef8', '2c75776b-7b41-4605-9223-6d8a317741ec', 'We started fish oil and a joint supplement at 6 as a preventative. Our vet recommended it specifically for the breed. The difference in Biscoff''s movement has been noticeable.', '2026-04-14 01:10:00+00'),
	('1405d442-ecf6-48b2-b1ee-677dfbd4513a', '36a5db88-a8a6-477d-9841-c4578ee64ef8', 'b68a1181-cd09-4d78-9322-11f47ba93926', 'Oatmeal isn''t there yet but we''re already doing the prep – shorter walks, more swim time, watching the stairs. Vet said goldens often mask discomfort until it''s significant.', '2026-04-14 01:45:00+00'),
	('a4ccb588-a6d7-49ef-b383-a66ce28d171a', '36a5db88-a8a6-477d-9841-c4578ee64ef8', '81e086b1-20aa-47ed-b286-dca03731a5df', 'The orthopedic bed made a huge difference for Penny. Also keeping them warm before the first walk of the day – they''re stiffest right after sleep.', '2026-04-14 02:18:00+00'),
	('0a9d4eb5-3682-4674-8732-be17f5f596d5', '51f15c9d-45f4-4aee-a143-6467b26e3313', '2c75776b-7b41-4605-9223-6d8a317741ec', 'Biscoff isn''t 8 yet but this made me a little emotional. Enjoy every slower walk. They''re still so happy.', '2026-04-14 01:15:00+00'),
	('86e89d1e-82ec-4aaa-b790-e27cdab5a709', '51f15c9d-45f4-4aee-a143-6467b26e3313', '66694e3f-9988-4378-9df3-671525ae0404', 'The joy doesn''t go anywhere even when the pace does. Chester sounds like a really good boy.', '2026-04-14 01:45:00+00'),
	('1fc6169e-ade2-4699-a54f-77def2e3ca6f', 'f15b8e18-955e-4ae0-8e53-7e958c0aeed8', '66694e3f-9988-4378-9df3-671525ae0404', 'Humphrey got into the compost once. Just carried a banana peel around like he''d found treasure.', '2026-04-14 01:10:00+00'),
	('57169244-59d9-4ae2-b164-091d26128a05', 'f15b8e18-955e-4ae0-8e53-7e958c0aeed8', 'b68a1181-cd09-4d78-9322-11f47ba93926', 'Oatmeal presents garden items to us like she grew them herself. Very proud.', '2026-04-14 01:35:00+00'),
	('d1c6e0ff-9e9c-434b-9ec9-92b78ecf1c6a', '7a997bc4-db75-4a9a-8e40-ed8def911e49', '2c75776b-7b41-4605-9223-6d8a317741ec', 'Biscoff would love this. We''re in.', '2026-04-14 01:05:00+00'),
	('6d7a123f-d12f-4ed8-9643-ed5fff9619c7', '7a997bc4-db75-4a9a-8e40-ed8def911e49', 'b68a1181-cd09-4d78-9322-11f47ba93926', 'Oatmeal is definitely in. She needs beach time.', '2026-04-14 01:18:00+00'),
	('3873e930-1e7e-49e4-bd69-ff3696a53d2b', '9f600fa9-7b6c-48f2-964b-f05f14097629', 'abfe51c1-74f5-44d9-b79e-19040c569bd3', 'Cricket came from a tough start too. The timeline really does vary – some weeks feel like huge progress and then something small spooks her again.', '2026-04-14 01:15:00+00'),
	('acd21313-f33e-4397-b6fc-6b2c45493984', '9f600fa9-7b6c-48f2-964b-f05f14097629', '7ca0959f-8881-4523-a053-c67cfb68a039', 'Fennel was feral for months in my house. Two years in she''s still working on some things. Thank you for sharing this.', '2026-04-14 01:45:00+00'),
	('6fe3eb7e-c70d-4829-80d6-7f9523d762e3', '9f600fa9-7b6c-48f2-964b-f05f14097629', 'b12ae1b3-95e0-472e-8454-724b01760e20', 'You''re rebuilding trust that was broken before you even met them. Sounds like she''s in exactly the right place.', '2026-04-14 02:18:00+00'),
	('28599337-d867-487d-9caf-2c82528744da', '7ebb1355-2bad-4375-9f70-efdd494a3877', '7ca0959f-8881-4523-a053-c67cfb68a039', 'With Fennel it was closer to 5 months before I saw real relaxation. The ''flinch less'' moment was a big milestone. Three months is still early.', '2026-04-14 01:10:00+00'),
	('6eb3f311-b0ed-46bb-a81a-04dec637633d', '7ebb1355-2bad-4375-9f70-efdd494a3877', 'b12ae1b3-95e0-472e-8454-724b01760e20', 'Some weeks feel like regression but they rarely are. Write down small wins – first time she ate with people in the room, first voluntary cuddle. The timeline for strays is very individual.', '2026-04-14 01:40:00+00'),
	('27369c9c-58a4-465f-8cad-86b52822dbf4', '7ebb1355-2bad-4375-9f70-efdd494a3877', 'abfe51c1-74f5-44d9-b79e-19040c569bd3', 'Cricket was on edge much longer than 3 months. Keep the environment predictable and don''t rush it.', '2026-04-14 02:12:00+00'),
	('bc81aeab-90d9-4197-b966-3650529c0281', 'd54ef66c-de23-4348-be47-1d582f41a3e8', '7a13f003-225f-47d7-a71a-6811a9ea4552', 'This is so sweet. Beets is almost at one year and it really does feel different. You start to trust each other.', '2026-04-14 01:10:00+00'),
	('f55ea05b-2a3d-4246-9d14-995f815c7796', 'd54ef66c-de23-4348-be47-1d582f41a3e8', 'f465c4d5-1fba-4183-b1f4-75540b37a66b', 'The first year is a lot of work and then you look up and you have a real partnership. Congrats.', '2026-04-14 01:35:00+00'),
	('2f23c856-049c-4f9a-a4fd-952ded8bcd98', '7cd6a8e2-78fd-4827-ba90-19e8562d7d1b', 'a99b104a-058a-4c4d-8cca-bfe7cd3ef522', 'Desi had GSD and terrier in her results and it explained the alert intensity. I stopped trying to override her instinct and started working with it instead.', '2026-04-14 01:10:00+00'),
	('756ff9e0-b5b1-41b8-9cb2-b7714819d0d1', '7cd6a8e2-78fd-4827-ba90-19e8562d7d1b', '7a13f003-225f-47d7-a71a-6811a9ea4552', 'Beets had results we didn''t expect and yes, it reframed some behaviors that were frustrating. Knowing the ''why'' helped.', '2026-04-14 01:40:00+00'),
	('5eab3961-6bcd-4e2b-9418-3af0e2013d50', 'b46f1284-a28b-4c80-8ff4-9d59ff6ddb3a', '7ca0959f-8881-4523-a053-c67cfb68a039', 'Fennel would love this! Mixed breed crew is always the best energy.', '2026-04-14 01:05:00+00'),
	('34d81ed8-77a6-4825-bb9b-10c926e47614', '757e8d90-9bc8-40fb-b33e-317805d24c58', '91916b03-243c-4a47-a02c-21a081f47ca2', 'Benny did this constantly as a puppy. It''s almost always reverse sneezing in pugs. Covering one nostril gently for a second can break the episode – ask your vet to demo it.', '2026-04-14 01:10:00+00'),
	('ad34fa5e-74b2-4d8c-8ca0-c965aee2e1d2', '757e8d90-9bc8-40fb-b33e-317805d24c58', '058648f9-dbb8-4158-8bcf-692704c167d8', 'It sounds terrifying the first time. The technique is: cover one nostril gently and stroke the throat. Usually stops within 30 seconds.', '2026-04-14 01:40:00+00'),
	('75a243a1-ab08-43a3-b530-dd29e909dbd0', '757e8d90-9bc8-40fb-b33e-317805d24c58', '9b9c57d2-f134-4dce-b01d-4fa2453cfcc7', 'Figgy does this after drinking water too fast. Totally normal for the breed, just unsettling to watch every time.', '2026-04-14 02:12:00+00'),
	('00f8afeb-66cb-4530-a9a9-ab9ada296240', 'ed313d7c-c5ea-4997-a33d-ea4b7344a522', '058648f9-dbb8-4158-8bcf-692704c167d8', 'We did it with Benny at 2 after he started really struggling in heat. Surgery was smoother than we expected and the difference was significant. He can exercise more and the snoring is way better.', '2026-04-14 01:15:00+00'),
	('0872ee7d-ccab-41a2-9542-ed39f3d5106c', 'ed313d7c-c5ea-4997-a33d-ea4b7344a522', 'ba78aed5-8e79-4d15-b004-9d6592b22112', 'Barnaby had a consult and the vet said moderate. We''re monitoring for now, but I know several pug owners who did it and don''t regret it at all.', '2026-04-14 01:45:00+00'),
	('69118b08-42ce-49e0-a904-738152255750', 'ed313d7c-c5ea-4997-a33d-ea4b7344a522', '1ca5417d-68de-42ae-8484-c1d4dd8c96c8', 'Noodles had it done at 18 months. Recovery was about 2 weeks and she''s been better since. Would do it again.', '2026-04-14 02:18:00+00'),
	('9a93d524-1c6a-44ce-adac-50972c0ab0c0', 'e068d958-3095-4b50-97ee-7a78663c263d', '058648f9-dbb8-4158-8bcf-692704c167d8', 'The snoring in that video is going to live rent-free in my head now.', '2026-04-14 01:10:00+00'),
	('2756e618-2f5d-4d29-bc8b-64093905dc61', 'e068d958-3095-4b50-97ee-7a78663c263d', 'd51e232f-794e-4ec2-a6a0-d22537fab73f', 'This is exactly the pug content I come here for.', '2026-04-14 01:30:00+00'),
	('4ded5511-0d5e-40b4-8787-cd20bcdd4af9', '0259037d-8d4e-4e57-a27e-fdf960470bc8', '91916b03-243c-4a47-a02c-21a081f47ca2', 'This is exactly the pug experience. You think you''re training them and then one day you realize they''ve been training you.', '2026-04-14 01:05:00+00'),
	('dec8f8b0-c564-442b-81ee-bd88117727f1', '0259037d-8d4e-4e57-a27e-fdf960470bc8', 'd51e232f-794e-4ec2-a6a0-d22537fab73f', 'Tulip invented a game where she brings me a toy and I''m only allowed to hold it for exactly 3 seconds. I''ve been playing it correctly for two years.', '2026-04-14 01:30:00+00'),
	('61102161-626d-4711-827e-877afaa1a1c5', '2f4afa4d-4baf-4441-a33b-d066d713d344', '91916b03-243c-4a47-a02c-21a081f47ca2', 'We don''t walk Benny between 9am and 7pm in summer. Mornings before 7:30 and evenings after 7:30. Kiddie pool in the shade for midday. It''s a whole season management thing.', '2026-04-14 01:10:00+00'),
	('74b096cd-3ae9-4eb2-9c4c-88ab4e713d86', '2f4afa4d-4baf-4441-a33b-d066d713d344', 'ba78aed5-8e79-4d15-b004-9d6592b22112', 'Barnaby actually refuses to go further when it''s too hot, which is pretty smart for a pug. We just let him lead the walk length in summer.', '2026-04-14 01:40:00+00'),
	('66569567-5982-42b8-9ff4-d8bd9cb965e7', '9595a1cd-49ca-4217-8d01-f2023e9f12cd', '91916b03-243c-4a47-a02c-21a081f47ca2', 'Benny and I are in. He loves seeing the flat faces.', '2026-04-14 01:05:00+00'),
	('80492fae-07bb-46c4-949c-e3354ec42116', '9595a1cd-49ca-4217-8d01-f2023e9f12cd', '058648f9-dbb8-4158-8bcf-692704c167d8', 'This is the event Benny has been waiting for.', '2026-04-14 01:20:00+00'),
	('5babe261-546d-441f-9bb7-c14d549704c5', '32ae8e23-cd3c-4cf6-a642-ce3bb6dda1c5', 'd51e232f-794e-4ec2-a6a0-d22537fab73f', 'Tulip had something similar once. Vet said superficial corneal inflammation – gave us drops and it cleared up. Definitely worth getting looked at sooner than later.', '2026-04-14 01:10:00+00'),
	('c578799e-8d05-421a-97e7-1e77be034715', '32ae8e23-cd3c-4cf6-a642-ce3bb6dda1c5', '1ca5417d-68de-42ae-8484-c1d4dd8c96c8', 'A vet really needs to see this. Pug eyes can get complicated fast. Right call posting it.', '2026-04-14 01:35:00+00'),
	('501fb277-18b4-4370-9e22-33255c481557', 'f542dc87-5140-489e-a5ae-a689df9f0d5d', '256dd24e-0f4d-4058-8c0c-736bbeb7aed4', 'Potato responds to food, tone of voice, and bribes. In that order. Nothing works once he''s decided not to engage.', '2026-04-14 01:10:00+00'),
	('a4237958-3d8d-4b98-8e87-813bf20f16be', 'f542dc87-5140-489e-a5ae-a689df9f0d5d', 'acf8d6dd-058d-4af2-a3e3-2cd3ac214c6f', 'Short sessions with high-value rewards. Archie checks out in about 5 minutes and you can see it happen. Stop before they disengage on their own.', '2026-04-14 01:35:00+00'),
	('2f26aced-203b-4e0b-9b80-15ad6da4efe8', 'f542dc87-5140-489e-a5ae-a689df9f0d5d', 'e9ef65bb-a15c-4cf4-9ca9-dfaa52f679de', 'Consistency and very short bursts. Gus loses interest fast and you can see it on his face.', '2026-04-14 02:08:00+00'),
	('bc0b9da1-3114-4d41-b6f5-e5ea1317f853', 'd8f55f1f-3c66-4622-a6b9-c2caba53cc2b', '256dd24e-0f4d-4058-8c0c-736bbeb7aed4', 'Potato stops every 20 feet to assess the situation. There''s no rushing it.', '2026-04-14 01:05:00+00'),
	('89da7ec8-7fe1-43cb-988b-e044ca53f42b', 'd8f55f1f-3c66-4622-a6b9-c2caba53cc2b', 'bceee679-3e77-4bf6-86f0-a050d5e3755f', 'They''re making an executive decision about whether the walk is worth their current energy level. Very deliberate.', '2026-04-14 01:25:00+00'),
	('eee26232-82a4-4df0-9147-248f8c2603d0', '8c5d2392-e573-4701-aca8-56fd3b874450', 'acf8d6dd-058d-4af2-a3e3-2cd3ac214c6f', 'Archie claimed our couch the first night and has never looked back. The dog bed is purely decorative.', '2026-04-14 01:05:00+00'),
	('3e647a03-ea49-4660-ae2c-59c5318bc27b', '8c5d2392-e573-4701-aca8-56fd3b874450', '256dd24e-0f4d-4058-8c0c-736bbeb7aed4', 'Potato''s dog bed exists as a monument to our naivety. It''s never been slept in.', '2026-04-14 01:25:00+00'),
	('6e7c822a-73cb-4ed2-a228-80777607f538', 'eeb9e7ea-0bc7-472f-91ac-a365f5f8e516', 'acf8d6dd-058d-4af2-a3e3-2cd3ac214c6f', 'We went through this with Archie. Changing protein source helped before going full elimination diet. Chicken is a common culprit for frenchies.', '2026-04-14 01:10:00+00'),
	('3e478e06-1f3f-4fec-9a29-b81a4c6b5c58', 'eeb9e7ea-0bc7-472f-91ac-a365f5f8e516', '256dd24e-0f4d-4058-8c0c-736bbeb7aed4', 'Potato had skin issues and we just switched to a limited ingredient food first. Not guaranteed but a reasonable first step before the full elimination process.', '2026-04-14 01:40:00+00'),
	('dadd5c2f-78d4-4ee7-9ebc-ba5377427c03', 'fabea6d1-a142-4deb-b234-a0b56eba7516', '256dd24e-0f4d-4058-8c0c-736bbeb7aed4', 'Potato and I are in. Early morning before it heats up is perfect for this breed.', '2026-04-14 01:05:00+00'),
	('cc54840b-22b2-4953-949d-325b07a4c8e4', 'fabea6d1-a142-4deb-b234-a0b56eba7516', '737ead19-798e-4d16-8701-05a499c1116b', 'Pascal loves Coronado. Count us in.', '2026-04-14 01:20:00+00'),
	('8d825d74-7d9c-4888-9086-ae3bcb3c7655', '96ea0f68-0a39-4bde-bd3e-19fd3c6add6f', '256dd24e-0f4d-4058-8c0c-736bbeb7aed4', 'Potato found a pill bug and absolutely lost his mind. Frenchies and insects are a whole genre.', '2026-04-14 01:10:00+00'),
	('43d623cc-c0e5-419c-be7f-b81316bc3955', '96ea0f68-0a39-4bde-bd3e-19fd3c6add6f', 'acf8d6dd-058d-4af2-a3e3-2cd3ac214c6f', 'Archie did this with a spider. I''ve never seen him move that fast. Pure theatrical horror.', '2026-04-14 01:35:00+00'),
	('d2ec5b1e-2029-4a67-bb72-a2beff827270', 'd51637c9-396c-4628-9aa9-25af860be3ad', 'fba595cb-23ac-4863-9e87-d98f4669bb96', 'Duke''s CGC certificate and his behavior in public have shifted some people''s reaction. I''ve accepted that some won''t see past the breed and put my energy toward the ones who will.', '2026-04-14 01:10:00+00'),
	('46db9556-b3ff-43d3-a330-f087e9938396', 'd51637c9-396c-4628-9aa9-25af860be3ad', '2a25bff8-1970-4821-a62b-006d005e941a', 'Ruthie gets the same. It used to sting. Now I use it as a chance to let her show who she actually is. Not everyone is interested but the ones who stop and meet her often leave with a different view.', '2026-04-14 01:40:00+00'),
	('507d65f5-f1f0-49fd-9cdb-8eeac2a3bf88', 'd51637c9-396c-4628-9aa9-25af860be3ad', '78f369f6-6ec8-404a-abb9-07d68e04a54d', 'Peanut is 3 now and a good ambassador. You know the dog you have.', '2026-04-14 02:12:00+00'),
	('5a55a978-7c8f-4562-af23-440098b2244a', 'd51637c9-396c-4628-9aa9-25af860be3ad', 'cc3cd22e-5f25-47e5-a249-4aba2b0e0cff', 'Clyde gets it too and he''s one of the most gentle dogs I''ve been around. Let the dog do the talking.', '2026-04-14 02:42:00+00'),
	('eee34e20-5461-4204-a89d-2c0b801bfe1b', 'afc2eb2e-b6f7-4622-85e9-d228abbeb8c6', '4e7b6512-e890-4e92-aaf2-e03daf6d5fd1', 'This is huge. Hank has a good temperament but we haven''t done the CGC yet. You''ve inspired me to actually sign up.', '2026-04-14 01:10:00+00'),
	('b755530a-e9eb-4170-afee-3d4b7bd62129', 'afc2eb2e-b6f7-4622-85e9-d228abbeb8c6', '2a25bff8-1970-4821-a62b-006d005e941a', 'Ruthie passed hers earlier this year. The test is not hard – they already know this stuff. It''s just proving it formally.', '2026-04-14 01:40:00+00'),
	('db1a2c36-a780-4293-b0dd-bc76136f263d', 'afc2eb2e-b6f7-4622-85e9-d228abbeb8c6', 'cc3cd22e-5f25-47e5-a249-4aba2b0e0cff', 'Clyde would nail the controlled greeting part. This is real motivation to get it done.', '2026-04-14 02:12:00+00'),
	('783b9b84-41d4-4ea1-8658-c46a99a57e87', '44df19b2-85bc-4e2d-b301-8090a0f7fdf0', 'fba595cb-23ac-4863-9e87-d98f4669bb96', 'The BAT method helped us a lot with Duke. It''s about letting the dog create distance from the trigger on their own terms. There are trainers in SD who specialize in it.', '2026-04-14 01:15:00+00'),
	('1a6ffc63-0d56-43bf-b8a5-39df342cf705', '44df19b2-85bc-4e2d-b301-8090a0f7fdf0', 'cc3cd22e-5f25-47e5-a249-4aba2b0e0cff', 'Start really far from the trigger and reward any calm behavior. You''re building a new pattern. It took us 6 months before Clyde could pass another dog on a normal sidewalk.', '2026-04-14 01:45:00+00'),
	('02dc3eba-57aa-480a-99b7-598ba2566420', '44df19b2-85bc-4e2d-b301-8090a0f7fdf0', '4565f55e-9e6c-443e-9d70-aebf4be04ddb', 'Margot had this. Parallel walking at distance with a reactive dog trainer made the most difference. The key is staying under threshold the whole time.', '2026-04-14 02:18:00+00'),
	('2d2c0647-80a7-4069-9455-85a7ddd05161', '9f469973-b587-4392-9cc8-afe56ef30b31', 'fba595cb-23ac-4863-9e87-d98f4669bb96', 'We put together a pet resume – vet references, CGC certificate, a photo of Duke being calm near kids. It worked for our current landlord.', '2026-04-14 01:10:00+00'),
	('3b7656e6-7247-45db-90e6-dd81a15383f9', '9f469973-b587-4392-9cc8-afe56ef30b31', 'cc3cd22e-5f25-47e5-a249-4aba2b0e0cff', 'Training certificates and vet history helped in our inquiry. Some places still said no. The ones who said yes after seeing it were better landlords anyway.', '2026-04-14 01:40:00+00'),
	('a898ef19-fba1-430d-92aa-fea500cecd31', '9f469973-b587-4392-9cc8-afe56ef30b31', '4565f55e-9e6c-443e-9d70-aebf4be04ddb', 'SD has a lot of breed-restricted buildings. Independent landlords are much more flexible than large property management companies. Worth targeting your search that way.', '2026-04-14 02:12:00+00'),
	('46fb0303-d0b5-4aee-b19a-735fa260c143', '12896c08-ab45-4d77-bd5f-6d9d929647d2', 'fba595cb-23ac-4863-9e87-d98f4669bb96', 'We''d love to come. Duke does really well in structured settings.', '2026-04-14 01:05:00+00'),
	('f84e40ef-146d-4048-8ff3-f857ba806a6e', '12896c08-ab45-4d77-bd5f-6d9d929647d2', '78f369f6-6ec8-404a-abb9-07d68e04a54d', 'Peanut and I are interested. The structured format sounds right for him.', '2026-04-14 01:20:00+00'),
	('9f7f65e3-65ea-49d9-8251-eb444316c5b6', '2c792eb2-2f9c-449e-a046-7f434f7531e1', '50234652-5ca9-46e2-98da-2d2d2ec2348e', 'Dot acts starving on a fixed measured amount every day. We''ve had the vet confirm healthy weight twice now. The performance is truly committed.', '2026-04-14 01:10:00+00'),
	('079a65bc-8d02-4476-b7fb-757ed1a51a57', '2c792eb2-2f9c-449e-a046-7f434f7531e1', 'e141f340-f521-4896-9f62-53b9f4a4576b', 'Fletcher has this energy. The vet says healthy and well-fed. Fletcher does not agree and will not accept this.', '2026-04-14 01:40:00+00'),
	('f72e2471-1ca8-4fc9-aa37-9fc5b21c0765', '2c792eb2-2f9c-449e-a046-7f434f7531e1', '639cc87e-c34a-4ddb-8ade-c22504320e3e', 'Olive has figured out that staring at my dinner plate with enough intensity sometimes results in food. She is not wrong.', '2026-04-14 02:12:00+00'),
	('e878d372-3da8-4f7c-bb12-6378f213002e', '62c1c738-8cfc-4ab2-a661-3b9b1433fc4c', '50234652-5ca9-46e2-98da-2d2d2ec2348e', 'Dot''s vet said Labs have an oral fixation tied to their retrieving history. The solution is removing everything chewable and providing unlimited appropriate alternatives. It does improve with age.', '2026-04-14 01:15:00+00'),
	('4a044edc-99be-492d-bb7a-887da1e21fe9', '62c1c738-8cfc-4ab2-a661-3b9b1433fc4c', 'e4f60a2b-b7ff-44cd-ba71-7ff8cad78b57', 'Bosley destroyed a chair cushion. Now he gets a rotation of frozen stuffed Kongs at departure. He''d rather have those.', '2026-04-14 01:45:00+00'),
	('758a4703-177f-4f89-b20d-6d8a99b80f2a', '62c1c738-8cfc-4ab2-a661-3b9b1433fc4c', 'e141f340-f521-4896-9f62-53b9f4a4576b', 'Fletcher did this at 10 months. Crating when unsupervised until they''re past the worst of it was our answer.', '2026-04-14 02:18:00+00'),
	('329a9fe6-d467-4cc9-82da-35deaee725dc', '04fca04d-96fa-4124-aa86-d38b8af5999d', 'e141f340-f521-4896-9f62-53b9f4a4576b', 'Fletcher brings his ball every single time I walk in. The joy is genuinely moving every time.', '2026-04-14 01:10:00+00'),
	('aa438fa9-fb40-429a-9718-224cbe8cbf4f', '04fca04d-96fa-4124-aa86-d38b8af5999d', 'e4f60a2b-b7ff-44cd-ba71-7ff8cad78b57', 'Bosley brings me a sock. Not my sock. Just finds one somewhere and presents it. It''s the thought.', '2026-04-14 01:35:00+00'),
	('9d06bbb4-5eee-411e-95b0-6cbca974ad6b', 'd87163cc-0e69-4a8d-bfc0-e0bb3e90d8de', 'e141f340-f521-4896-9f62-53b9f4a4576b', 'Fletcher would be in his element at Mission Bay. We''ll try to come.', '2026-04-14 01:05:00+00'),
	('048006d8-42bb-445d-96a6-c00b30ea873f', 'd87163cc-0e69-4a8d-bfc0-e0bb3e90d8de', '50234652-5ca9-46e2-98da-2d2d2ec2348e', 'Dot needs this kind of outlet. We''re interested.', '2026-04-14 01:20:00+00'),
	('bafe335a-d3d9-497a-9aa5-0c8ba314abee', '3c17d44b-762f-4673-90b0-1ebe9cdcef46', '50234652-5ca9-46e2-98da-2d2d2ec2348e', 'Dot does the same with our garden hose. The level of commitment is very lab.', '2026-04-14 01:10:00+00'),
	('9ce10dd1-10c9-4155-af60-e79770473188', '3c17d44b-762f-4673-90b0-1ebe9cdcef46', 'e141f340-f521-4896-9f62-53b9f4a4576b', 'Fletcher sat in a neighbor''s sprinkler for 20 minutes. Total peace.', '2026-04-14 01:35:00+00'),
	('42c76af6-7de6-4dd9-a25e-dd67b43d0955', '4d53e1a9-b55e-47ee-9a98-04411307908a', '93765c03-ccb5-4ea5-9032-5258c5c49c9e', 'Radar at Dog Beach is the same energy. Pure joy and zero sense of personal space.', '2026-04-14 01:10:00+00'),
	('7be764d1-0936-4cd2-a222-e26c2bbb3931', '4d53e1a9-b55e-47ee-9a98-04411307908a', '2f4504af-8ad4-4108-80c7-ef0fb81df27a', 'This is exactly what the breed is for.', '2026-04-14 01:30:00+00'),
	('ba41c14e-0cee-4ace-b3dd-8d3c8bdeba57', 'c3435817-442b-4053-9b08-2680908ab2d9', '15fe21df-d12b-4ac4-bac3-d70a7f2d9321', 'We were told ''compact'' and ended up with 65 lbs. Compact by some other metric apparently.', '2026-04-14 01:10:00+00'),
	('d4dd807f-6270-4d94-8fb2-ca75a02aa800', 'c3435817-442b-4053-9b08-2680908ab2d9', '4c305992-e9fc-45ea-b9d8-58fc72b2a27b', 'Cosmo kept growing past 14 months. The mini/standard distinction is not as precise as breeders suggest.', '2026-04-14 01:40:00+00'),
	('ef4c04b6-b454-45f3-97ac-c911fa4e4d4b', 'e590490b-0720-4b9e-b2cd-964a0a902fba', 'd51d0953-9f02-4028-b400-0b9acda89735', 'This is essentially Teddy''s story too. He graduated from promising service trainee to excellent pet. Different job, still a good one.', '2026-04-14 01:10:00+00'),
	('d340afbb-be42-4e18-aa94-bf625f09133c', 'e590490b-0720-4b9e-b2cd-964a0a902fba', '15fe21df-d12b-4ac4-bac3-d70a7f2d9321', 'The dogs who almost made it through service training seem to make the most personable pets. All the training, none of the restriction.', '2026-04-14 01:40:00+00'),
	('d71cd701-f0d8-47a8-8a28-276fce53ac76', '2de62d17-5620-4068-952d-7ad80110a7e6', 'd51d0953-9f02-4028-b400-0b9acda89735', 'Teddy is classic lab – wants to retrieve, wants everyone to be happy, zero stubbornness. Full lab personality with a curly coat.', '2026-04-14 01:10:00+00'),
	('d7453802-d865-450d-8b7b-fe59b97594a1', '2de62d17-5620-4068-952d-7ad80110a7e6', '15fe21df-d12b-4ac4-bac3-d70a7f2d9321', 'Our labradoodle is all poodle brain. Intense focus, picks up commands fast, has opinions about everything.', '2026-04-14 01:40:00+00'),
	('70e0d298-9472-4d22-9247-e19de1413ff3', '1ed331ac-2336-44ee-94c7-be4934bf1613', '27901cf6-7b3e-4aff-8b1d-749267dc2287', 'We''d love to do Los Peñasquitos. When do you usually go?', '2026-04-14 01:05:00+00'),
	('53b3f8a0-89a3-4a94-ad14-2bd002aaa5fd', '1ed331ac-2336-44ee-94c7-be4934bf1613', '2f4504af-8ad4-4108-80c7-ef0fb81df27a', 'That trail is great for labradoodles. We''re potentially interested.', '2026-04-14 01:20:00+00'),
	('8cbb19c3-6812-4f69-b3e8-0e7d1bc5fb0f', '3d1a9513-9c33-45a6-ba76-9d41da5b6154', 'd51d0953-9f02-4028-b400-0b9acda89735', 'Teddy is technically past puppy stage but not past puppy energy. Can we still come?', '2026-04-14 01:05:00+00'),
